import sys

def solve():
    import sys
    input = sys.stdin.read
    data = input().split()
    N = int(data[0])
    A = data[1]

    length = 3 ** N
    current = list(A)

    for _ in range(N):
        next_len = 3 ** (N - _ - 1)
        next_str = []
        for i in range(next_len):
            group = current[3*i:3*i+3]
            count_0 = group.count('0')
            count_1 = group.count('1')
            if count_0 > count_1:
                next_str.append('0')
            else:
                next_str.append('1')
        current = next_str

    target = '0' if current[0] == '1' else '1'

    # Now, work backwards to find the minimum changes needed
    dp = [ [float('inf')] * 2 for _ in range(N + 1) ]
    dp[0][int(current[0])] = 0

    for level in range(1, N + 1):
        for bit in range(2):
            for group_idx in range(3 ** (level - 1)):
                start = 3 ** (N - level) * group_idx
                end = start + 3 ** (N - level)
                count_0 = 0
                count_1 = 0
                for i in range(start, end):
                    if A[i] == '0':
                        count_0 += 1
                    else:
                        count_1 += 1
                # To get majority bit, need more than half
                min_changes = float('inf')
                if count_0 > count_1:
                    if bit == 0:
                        min_changes = 0
                    else:
                        min_changes = count_1
                elif count_1 > count_0:
                    if bit == 1:
                        min_changes = 0
                    else:
                        min_changes = count_0
                else:
                    if bit == 0:
                        min_changes = 1
                    else:
                        min_changes = 1
                if dp[level - 1][bit] + min_changes < dp[level][bit]:
                    dp[level][bit] = dp[level - 1][bit] + min_changes

    print(dp[N][int(target)])

